# Save
with open(blog_path, 'w', encoding='utf-8') as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

# Verify word counts
with open(blog_path, 'r', encoding='utf-8') as f:
    data = json.load(f)
total = 0
for slug, post in data['posts'].items():
    content = post.get('content', {})
    wc = len(content.get('intro', '').split()) + len(content.get('conclusion', '').split())
    for s in content.get('sections', []):
        wc += len(s.get('content', '').split()) + len(s.get('title', '').split())
        for item in s.get('list', []):
            wc += len(item.split())
    total += wc
    print(f'{slug}: {wc} words, {len(content.get("sections", []))} sections')
print(f'\nTotal: {total} words')
